```go
// pkg/testutil/http_helper.go
package testutil

import (
    "bytes"
    "encoding/json"
    "net/http"
    "net/http/httptest"
    "testing"
)

type HTTPTestHelper struct {
    t *testing.T
}

func NewHTTPTestHelper(t *testing.T) *HTTPTestHelper {
    return &HTTPTestHelper{t: t}
}

func (h *HTTPTestHelper) MakeRequest(
    method, path string,
    body interface{},
    handler http.HandlerFunc,
) *httptest.ResponseRecorder {
    var reqBody []byte
    var err error
    
    if body != nil {
        reqBody, err = json.Marshal(body)
        if err != nil {
            h.t.Fatalf("Failed to marshal request body: %v", err)
        }
    }
    
    req := httptest.NewRequest(method, path, bytes.NewBuffer(reqBody))
    req.Header.Set("Content-Type", "application/json")
    
    rr := httptest.NewRecorder()
    handler.ServeHTTP(rr, req)
    
    return rr
}

func (h *HTTPTestHelper) AssertStatusCode(rr *httptest.ResponseRecorder, expected int) {
    if rr.Code != expected {
        h.t.Errorf("Expected status code %d, got %d", expected, rr.Code)
    }
}

func (h *HTTPTestHelper) ParseResponse(rr *httptest.ResponseRecorder, v interface{}) {
    if err := json.Unmarshal(rr.Body.Bytes(), v); err != nil {
        h.t.Fatalf("Failed to parse response: %v", err)
    }
}
