### Flaky Test Model

```go
// pkg/testutil/flaky_test.go
package testutil

import "time"

type FlakyTestRecord struct {
    TestID          string    `json:"test_id"`
    TestName        string    `json:"test_name"`
    ExecutionCount  int       `json:"execution_count"`
    FailureCount    int       `json:"failure_count"`
    FlakyRate       float64   `json:"flaky_rate"`
    LastFailure     time.Time `json:"last_failure"`
    IsQuarantined   bool      `json:"is_quarantined"`
    Recommendation  string    `json:"recommendation"`
}

type FlakyTestDetector struct {
    history map[string][]TestExecution
}

type TestExecution struct {
    Timestamp time.Time
    Status    string // "passed" or "failed"
    Duration  int64
}

func NewFlakyTestDetector() *FlakyTestDetector {
    return &FlakyTestDetector{
        history: make(map[string][]TestExecution),
    }
}

func (d *FlakyTestDetector) RecordExecution(testName string, status string, duration int64) {
    execution := TestExecution{
        Timestamp: time.Now(),
        Status:    status,
        Duration:  duration,
    }
    
    d.history[testName] = append(d.history[testName], execution)
    
    // Keep only last 100 executions
    if len(d.history[testName]) > 100 {
        d.history[testName] = d.history[testName][1:]
    }
}

func (d *FlakyTestDetector) IsFlaky(testName string) bool {
    executions := d.history[testName]
    if len(executions) < 10 {
        return false
    }
    
    // Check last 10 executions
    recent := executions[len(executions)-10:]
    failures := 0
    
    for _, exec := range recent {
        if exec.Status == "failed" {
            failures++
        }
    }
    
    // Flaky if 3+ failures in last 10 executions
    if failures >= 3 {
        return true
    }
    
    // Check for alternating pattern
    alternating := 0
    for i := 1; i < len(recent); i++ {
        if recent[i].Status != recent[i-1].Status {
            alternating++
        }
    }
    
    // Flaky if 5+ alternations in last 10 executions
    return alternating >= 5
}

func (d *FlakyTestDetector) GetRecommendation(testName string) string {
    executions := d.history[testName]
    if len(executions) == 0 {
        return "No recommendation available"
    }
    
    // Analyze failure patterns
    var totalDuration int64
    for _, exec := range executions {
        totalDuration += exec.Duration
    }
    avgDuration := totalDuration / int64(len(executions))
    
    if avgDuration > 5000 {
        return "Consider increasing timeout or optimizing test performance"
    }
    
    return "Add explicit waits or improve test isolation"
}
